/********************************************
    CCDA ROUTER LEVEL VALIDATION (LIGHT ONLY)
********************************************/

var isCCDASubmit = (
    requestedPath == "/ccda/Bundle/" ||
    requestedPath == "/ccda/Bundle"
);

var isCCDAValidate = (
    requestedPath == "/ccda/Bundle/$validate/" ||
    requestedPath == "/ccda/Bundle/$validate"
);

if (isCCDASubmit || isCCDAValidate) {

	function checkRequiredHeader(headerName, mapKey) {
	    var value = $('headers').getHeader(headerName);

	    if (!value || String(value).trim() === "") {
	        missingHeaders.push("Missing required header " + headerName);
	        //missingHeaders.push(headerName);
	    } else {
	        channelMap.put(mapKey || headerName, value);
	    }
	}


    logger.info("CCDA request detected in Router");

    var missingHeaders = [];

    // ✅ Content-Type (light check only)
    var contentType = $('headers').getHeader('Content-Type');
    if (!contentType || !contentType.startsWith('multipart/form-data')) {
        missingHeaders.push("Content-Type must be multipart/form-data");
    }

    // ✅ Raw data presence
    var rawData = connectorMessage.getRawData();
    if (!rawData || rawData.trim().length === 0) {
        missingHeaders.push("Uploaded file is empty");
    }

    // ✅ Only for SUBMIT (not validate)
    if (isCCDASubmit) {
        logger.info("CCDA SUBMIT flow");
        checkRequiredHeader('X-TechBD-Tenant-ID', 'tenantId');
    	   checkRequiredHeader('X-TechBD-CIN', 'patientCIN');
 	   checkRequiredHeader('X-TechBD-Facility-ID', 'facilityId');
    	   checkRequiredHeader('X-TechBD-Encounter-Type', 'encounterType');


        // NPI / TIN
        var npi = $('headers').getHeader('X-TechBD-OrgNPI');
        var tin = $('headers').getHeader('X-TechBD-OrgTIN');

        if ((!npi || npi.trim() === "") && (!tin || tin.trim() === "")) {
            missingHeaders.push("Either X-TechBD-OrgNPI or X-TechBD-OrgTIN required");
        } else {
            if (npi) channelMap.put('organizationNPI', npi);
            if (tin) channelMap.put('organizationTIN', tin);
        }
    }

    // ✅ VALIDATE flow → minimal only
    if (isCCDAValidate) {
        logger.info("CCDA VALIDATE flow (light validation only)");
        // ❌ DO NOT enforce CIN / Facility / Encounter
    }

    if (missingHeaders.length > 0) {
        var errorMessage = "Bad Request : " + missingHeaders.join(", ");
        logger.error(errorMessage);
        responseMap.put('status', '400');
        setErrorResponse(400, errorMessage);
        throw new Error(errorMessage);
    }

    logger.info("CCDA router validation passed");
}

/**
* Util function to generate json string wit hstatus and message
*/
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', statusCode);

    responseMap.put('finalResponse', JSON.stringify({
        status: statusCode,
        error: errorMessage
    }));
}

